class UpdateChecker(QThread):
    update_available = Signal(str)
    def run(self):
        try:
            req = urllib.request.Request("https://api.github.com/repos/farazkayan/nexus-workflow-manager/releases/latest", headers={'User-Agent': 'Nexus-App'})
            with urllib.request.urlopen(req, timeout=5) as response:
                data = json.loads(response.read().decode('utf-8'))
                tag = data.get("tag_name", "").lstrip("v")
                current = VERSION.lstrip("v")
                def parse_version(v):
                    v_clean = v.split('-')[0]
                    return tuple(int(p) if p.isdigit() else 0 for p in v_clean.split('.'))
                if tag and parse_version(tag) > parse_version(current):
                    self.update_available.emit(tag)
        except Exception: pass

class ScheduleChecker(QThread):
    trigger_workflow = Signal(str)
    def __init__(self, parent=None):
        super().__init__(parent)
        self.running = True
        self.workflows = {}
    def update_workflows(self, workflows):
        self.workflows = dict(workflows)
    def run(self):
        last_triggered = {}
        while self.running:
            now = datetime.now()
            current_time = now.strftime("%H:%M")
            current_day = now.weekday()
            current_day_str = now.strftime("%Y-%m-%d")
            for name, w_data in self.workflows.items():
                if w_data.get("schedule_enabled", False):
                    if w_data.get("schedule_time") == current_time:
                        if current_day in w_data.get("schedule_days", []):
                            trigger_key = f"{name}_{current_day_str}_{current_time}"
                            if trigger_key not in last_triggered:
                                last_triggered[trigger_key] = True
                                self.trigger_workflow.emit(name)
            time.sleep(10)

class WorkflowExecutor(QThread):
    finished_all = Signal(list)
    def __init__(self, urls, apps, launch_delay=1.5, parent=None):
        super().__init__(parent)
        self.urls = urls
        self.apps = apps
        self.launch_delay = launch_delay
        self.errors = []
    def run(self):
        for i, url in enumerate(self.urls):
            try: 
                if sys.platform == "win32":
                    os.startfile(url)
                elif sys.platform == "darwin":
                    subprocess.Popen(["open", url])
                else:
                    subprocess.Popen(["xdg-open", url])
            except Exception as e: 
                self.errors.append(f"Failed to open URL: {url} ({e})")
            if i < len(self.urls) - 1 or len(self.apps) > 0:
                time.sleep(self.launch_delay)
        for app_path in self.apps:
            try:
                if sys.platform == "win32":
                    os.startfile(app_path)
                elif sys.platform == "darwin":
                    subprocess.Popen(["open", app_path])
                else:
                    subprocess.Popen(["xdg-open", app_path])
            except Exception as e:
                self.errors.append(f"Failed to launch app: {os.path.basename(app_path)} ({e})")
        self.finished_all.emit(self.errors)

class NexusAPIHandler(BaseHTTPRequestHandler):
    app_ref = None
    def log_message(self, format, *args): pass
    def _cors(self):
        self.send_header("Access-Control-Allow-Origin", "*")
        self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
        self.send_header("Access-Control-Allow-Headers", "Content-Type")
    def do_OPTIONS(self):
        self.send_response(200); self._cors(); self.end_headers()
    def do_GET(self):
        app = NexusAPIHandler.app_ref
        if self.path == "/status":
            self._json({"status": "running", "version": VERSION})
        elif self.path == "/workflows":
            if not app: self._json({"error": "not_ready"}, 503); return
            data = {}
            for name, w in app.bridge._workflows.items():
                data[name] = {"emoji": w.get("emoji", "🚀"), "description": w.get("description", ""), "item_count": len(w.get("apps",[])) + len(w.get("urls",[])), "category": w.get("category", "General"), "last_run": w.get("last_run", ""), "pinned": w.get("pinned", False)}
            self._json({"workflows": data})
        else: self._json({"error": "not_found"}, 404)
    def do_POST(self):
        length = int(self.headers.get("Content-Length", 0))
        body = json.loads(self.rfile.read(length)) if length else {}
        app = NexusAPIHandler.app_ref
        if not app: self._json({"error": "not_ready"}, 503); return
        if self.path == "/launch":
            name = body.get("name", "")
            if name not in app.bridge._workflows:
                self._json({"error": "not_found"}, 404); return
            QMetaObject.invokeMethod(app.bridge, "runWorkflow", Qt.QueuedConnection, Q_ARG(str, name))
            self._json({"status": "ok"})
        elif self.path == "/add-url":
            url = body.get("url",""); wf = body.get("workflow","")
            if wf not in app.bridge._workflows: self._json({"error": "not_found"}, 404); return
            if url and url not in app.bridge._workflows[wf]["urls"]:
                app.bridge._workflows[wf]["urls"].append(url)
                app.bridge._save_workflows()
                app.bridge.workflowsChanged.emit(app.bridge._get_state_json())
            self._json({"status": "ok"})
        elif self.path == "/create-workflow":
            name = body.get("name","Untitled"); urls = body.get("urls",[])
            final = name; i = 1
            while final in app.bridge._workflows:
                final = f"{name} ({i})"; i += 1
            app.bridge._workflows[final] = {"description": "Created from Chrome", "emoji": "🌐", "color": "Default", "apps": [], "urls": [u for u in urls if u.startswith("http")], "pinned": False, "category": "General", "run_count": 0}
            app.bridge._save_workflows()
            app.bridge.workflowsChanged.emit(app.bridge._get_state_json())
            self._json({"status": "ok", "name": final})
        else: self._json({"error": "not_found"}, 404)
    def _json(self, data, code=200):
        body = json.dumps(data).encode()
        self.send_response(code); self._cors()
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", len(body))
        self.end_headers(); self.wfile.write(body)

class NexusAPIServer(threading.Thread):
    PORT = 57832
    def __init__(self, app_instance):
        super().__init__(daemon=True)
        NexusAPIHandler.app_ref = app_instance
        self._server = HTTPServer(("127.0.0.1", self.PORT), NexusAPIHandler)
    def run(self): self._server.serve_forever()
    def stop(self): self._server.shutdown()

class GlobalHotkeyManager:
    MOD_CONTROL = 0x0002
    MOD_SHIFT   = 0x0004
    MOD_ALT     = 0x0001
    MOD_WIN     = 0x0008
    VK_MAP = {
        "a":0x41,"b":0x42,"c":0x43,"d":0x44,"e":0x45,"f":0x46,"g":0x47,
        "h":0x48,"i":0x49,"j":0x4A,"k":0x4B,"l":0x4C,"m":0x4D,"n":0x4E,
        "o":0x4F,"p":0x50,"q":0x51,"r":0x52,"s":0x53,"t":0x54,"u":0x55,
        "v":0x56,"w":0x57,"x":0x58,"y":0x59,"z":0x5A,
        "0":0x30,"1":0x31,"2":0x32,"3":0x33,"4":0x34,
        "5":0x35,"6":0x36,"7":0x37,"8":0x38,"9":0x39,
        "f1":0x70,"f2":0x71,"f3":0x72,"f4":0x73,"f5":0x74,
        "f6":0x75,"f7":0x76,"f8":0x77,"f9":0x78,"f10":0x79,
        "f11":0x7A,"f12":0x7B,
        "space":0x20,"enter":0x0D,"tab":0x09,"backspace":0x08,
        "delete":0x2E,"insert":0x2D,"home":0x24,"end":0x23,
        "page up":0x21,"page down":0x22,
        "up":0x26,"down":0x28,"left":0x25,"right":0x27,
    }
    def __init__(self, hwnd):
        self.hwnd = hwnd
        self._registered = {}
        self._next_id = 3000
    def parse(self, hk_str):
        if not hk_str: return None
        parts = [p.strip().lower() for p in hk_str.split("+")]
        mods, key = 0, None
        for p in parts:
            if p == "ctrl": mods |= self.MOD_CONTROL
            elif p == "shift": mods |= self.MOD_SHIFT
            elif p == "alt": mods |= self.MOD_ALT
            elif p == "win": mods |= self.MOD_WIN
            else: key = p
        if not key or key not in self.VK_MAP: return None
        return mods, self.VK_MAP[key]
    def register_all(self, workflows):
        self.unregister_all()
        for name, data in workflows.items():
            parsed = self.parse(data.get("hotkey", ""))
            if not parsed: continue
            mods, vk = parsed
            hk_id = self._next_id; self._next_id += 1
            if ctypes.windll.user32.RegisterHotKey(int(self.hwnd), hk_id, mods, vk):
                self._registered[hk_id] = name
    def unregister_all(self):
        for hk_id in self._registered:
            ctypes.windll.user32.UnregisterHotKey(int(self.hwnd), hk_id)
        self._registered.clear()
        self._next_id = 3000
    def get_name(self, hk_id):
        return self._registered.get(hk_id)

class NexusBridge(QObject):
    workflowsChanged   = Signal(str)
    statusMessage      = Signal(str)
    updateAvailable    = Signal(str)
    filePickerResult   = Signal(str)
    def __init__(self):
        super().__init__()
        self._profile_data = self._load_profiles()
        self._settings     = self._load_settings()
        active = self._profile_data.get("active", "Default")
        self._workflows    = self._profile_data["profiles"].get(active, {})
    def _get_state_json(self):
        active = self._profile_data.get("active", "Default")
        profiles = list(self._profile_data.get("profiles", {}).keys())
        custom_cats = self._settings.get("custom_categories", [])
        all_cats = list(CATEGORIES)
        for c in custom_cats:
            if c not in all_cats: all_cats.append(c)
        for w in self._workflows.values():
            c = w.get("category","General")
            if c not in all_cats: all_cats.append(c)
        return json.dumps({
            "workflows": self._workflows,
            "active_profile": active,
            "profiles": profiles,
            "settings": self._settings,
            "categories": all_cats,
        })
    def _save_workflows(self):
        active = self._profile_data["active"]
        self._profile_data["profiles"][active] = self._workflows
        with open(PROFILES_FILE, "w") as f:
            json.dump(self._profile_data, f, indent=4)
        if hasattr(self, "_hotkey_mgr") and self._hotkey_mgr:
            self._hotkey_mgr.register_all(self._workflows)
    def _load_profiles(self):
        if os.path.exists(PROFILES_FILE):
            try:
                with open(PROFILES_FILE) as f:
                    d = json.load(f)
                    if "profiles" in d and "active" in d: return d
            except: pass
        data = {"active":"Default","profiles":{"Default":{}}}
        if os.path.exists(WORKFLOWS_FILE):
            try:
                with open(WORKFLOWS_FILE) as f:
                    data["profiles"]["Default"] = json.load(f)
            except: pass
        return data
    def _load_settings(self):
        if os.path.exists(SETTINGS_FILE):
            try:
                with open(SETTINGS_FILE) as f: return json.load(f)
            except: pass
        return {"theme":"Dark","launch_delay":1.5,"compact_mode":False}
    def _save_settings(self):
        with open(SETTINGS_FILE,"w") as f:
            json.dump(self._settings, f)
        if sys.platform == "win32":
            try:
                key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, r"Software\Microsoft\Windows\CurrentVersion\Run", 0, winreg.KEY_SET_VALUE)
                if self._settings.get("run_on_startup"):
                    path = sys.executable if getattr(sys, 'frozen', False) else os.path.abspath(sys.argv[0])
                    winreg.SetValueEx(key, "Nexus", 0, winreg.REG_SZ, f'"{path}"')
                else:
                    try: winreg.DeleteValue(key, "Nexus")
                    except FileNotFoundError: pass
                winreg.CloseKey(key)
            except Exception: pass
    @Slot()
    def requestState(self):
        self.workflowsChanged.emit(self._get_state_json())
    @Slot(str)
    def runWorkflow(self, name):
        if name not in self._workflows: return
        data = self._workflows[name]
        self._workflows[name]["last_run"]  = datetime.now().isoformat()
        self._workflows[name]["run_count"] = self._workflows[name].get("run_count",0)+1
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"🚀 Launching {name}...")
        executor = WorkflowExecutor(data.get("urls",[]), data.get("apps",[]), self._settings.get("launch_delay", 1.5), parent=self)
        executor.finished_all.connect(lambda errs: self.statusMessage.emit("⚠️ Some items failed" if errs else f"✅ {name} launched"))
        executor.start()
    @Slot(str)
    def createWorkflow(self, json_str):
        d = json.loads(json_str)
        name = d.get("name","").strip()
        if not name: return
        if name in self._workflows:
            self.statusMessage.emit("❌ A workflow with that name already exists"); return
        self._workflows[name] = {"description": d.get("description",""), "color": d.get("color","Default"), "emoji": d.get("emoji","🚀"), "apps": d.get("apps",[]), "urls": d.get("urls",[]), "pinned": False, "category": d.get("category","General"), "schedule_enabled": False, "schedule_time": "09:00", "schedule_days": [], "hotkey": "", "run_count": 0, "last_run": None}
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"✅ '{name}' created")
    @Slot(str, str)
    def editWorkflow(self, old_name, json_str):
        if old_name not in self._workflows: return
        d = json.loads(json_str)
        name = d.get("name","").strip()
        if not name: return
        if name != old_name and name in self._workflows:
            self.statusMessage.emit("❌ Name already exists"); return
        existing = self._workflows.pop(old_name)
        self._workflows[name] = {**existing, "description": d.get("description",""), "color": d.get("color","Default"), "emoji": d.get("emoji","🚀"), "apps": d.get("apps",[]), "urls": d.get("urls",[]), "category": d.get("category","General")}
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"✅ '{name}' updated")
    @Slot(str)
    def deleteWorkflow(self, name):
        self._workflows.pop(name, None)
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"🗑️ '{name}' deleted")
    @Slot(str)
    def duplicateWorkflow(self, name):
        if name not in self._workflows: return
        new = name+" (Copy)"; i=1
        while new in self._workflows: new = f"{name} (Copy {i})"; i+=1
        self._workflows[new] = self._workflows[name].copy()
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"✅ Duplicated '{name}'")
    @Slot(str)
    def togglePin(self, name):
        if name not in self._workflows: return
        self._workflows[name]["pinned"] = not self._workflows[name].get("pinned",False)
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
    @Slot(str, str, str, str)
    def setSchedule(self, name, enabled_str, time_str, days_json):
        if name not in self._workflows: return
        self._workflows[name]["schedule_enabled"] = enabled_str == "true"
        self._workflows[name]["schedule_time"] = time_str
        self._workflows[name]["schedule_days"] = json.loads(days_json)
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit("✅ Schedule saved")
    @Slot(str, str)
    def setHotkey(self, name, hotkey):
        if name not in self._workflows: return
        self._workflows[name]["hotkey"] = hotkey
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"✅ Hotkey set to '{hotkey}'" if hotkey else "✅ Hotkey cleared")
    @Slot(str, str)
    def reorderWorkflows(self, source, target):
        if source == target or source not in self._workflows: return
        keys = list(self._workflows.keys())
        try:
            si, ti = keys.index(source), keys.index(target)
            keys.pop(si); keys.insert(ti, source)
            self._workflows = {k: self._workflows[k] for k in keys}
            self._save_workflows()
            self.workflowsChanged.emit(self._get_state_json())
        except ValueError: pass
    @Slot(str)
    def switchProfile(self, name):
        if name not in self._profile_data["profiles"]: return
        self._profile_data["active"] = name
        self._workflows = self._profile_data["profiles"][name]
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"Switched to '{name}'")
    @Slot(str)
    def createProfile(self, name):
        name = name.strip()
        if not name or name in self._profile_data["profiles"]: return
        self._profile_data["profiles"][name] = {}
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit(f"✅ Profile '{name}' created")
    @Slot(str)
    def deleteProfile(self, name):
        if name == "Default" or name not in self._profile_data["profiles"]: return
        del self._profile_data["profiles"][name]
        if self._profile_data["active"] == name:
            self._profile_data["active"] = "Default"
            self._workflows = self._profile_data["profiles"]["Default"]
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
    @Slot(str)
    def saveSettings(self, json_str):
        self._settings.update(json.loads(json_str))
        self._save_settings()
        self.workflowsChanged.emit(self._get_state_json())
    @Slot(str)
    def addCategory(self, name):
        name = name.strip()
        if not name: return
        custom = self._settings.get("custom_categories",[])
        if name not in custom and name not in CATEGORIES:
            custom.append(name)
            self._settings["custom_categories"] = custom
            self._save_settings()
        self.workflowsChanged.emit(self._get_state_json())
    @Slot()
    def resetStats(self):
        for w in self._workflows.values(): w["run_count"] = 0
        self._save_workflows()
        self.workflowsChanged.emit(self._get_state_json())
        self.statusMessage.emit("✅ Stats reset")
    @Slot()
    def openFilePicker(self):
        import sys
        from PySide6.QtWidgets import QApplication
        if sys.platform == "win32":
            filter_str = "Executables (*.exe);;All Files (*.*)"
        elif sys.platform == "darwin":
            filter_str = "Applications (*.app);;All Files (*)"
        else:
            filter_str = "All Files (*)"
        parent = QApplication.activeWindow()
        path, _ = QFileDialog.getOpenFileName(parent, "Select Application", "", filter_str)
        self.filePickerResult.emit(path or "")
    @Slot()
    def exportWorkflows(self):
        path, _ = QFileDialog.getSaveFileName(None, "Export Workflows", "nexus_workflows.json", "JSON (*.json)")
        if path:
            try:
                with open(path,"w") as f: json.dump(self._workflows,f,indent=4)
                self.statusMessage.emit(f"✅ Exported to {os.path.basename(path)}")
            except Exception as e: self.statusMessage.emit(f"❌ Export failed: {e}")
    @Slot()
    def importWorkflows(self):
        path, _ = QFileDialog.getOpenFileName(None, "Import Workflows", "", "JSON (*.json)")
        if not path: return
        try:
            with open(path) as f: data = json.load(f)
            valid = {k:v for k,v in data.items() if isinstance(v,dict) and "urls" in v and "apps" in v}
            if not valid: self.statusMessage.emit("❌ No valid workflows found in file"); return
            self._workflows.update(valid)
            self._save_workflows()
            self.workflowsChanged.emit(self._get_state_json())
            self.statusMessage.emit(f"✅ Imported {len(valid)} workflows")
        except Exception as e: self.statusMessage.emit(f"❌ Import failed: {e}")
    @Slot(str)
    def checkBrokenPaths(self, name):
        if name not in self._workflows: return
        broken = [a for a in self._workflows[name].get("apps",[]) if not os.path.exists(a)]
        self.statusMessage.emit(f"⚠️ {len(broken)} broken path(s) in '{name}'" if broken else f"✅ All paths in '{name}' are valid")

