class MainWindow(QMainWindow):
    def __init__(self, bridge):
        super().__init__()
        self._generate_icon()
        self.bridge  = bridge
        self.setWindowTitle("Nexus")
        self.resize(1100, 700)
        self.setMinimumSize(700, 500)
        self.setWindowIcon(self.app_icon)

        self.view    = QWebEngineView()
        self.channel = QWebChannel()
        self.channel.registerObject("bridge", bridge)
        self.view.page().setWebChannel(self.channel)
        self.view.setHtml(HTML, QUrl("qrc:/"))
        self.setCentralWidget(self.view)

        settings = bridge._settings
        if "geometry" in settings:
            self.restoreGeometry(QByteArray.fromBase64(settings["geometry"].encode()))

        self.tray = QSystemTrayIcon(self.app_icon, self)
        self.tray_menu = QMenu()
        show_act = QAction("Show Nexus", self)
        show_act.triggered.connect(self.showNormal)
        quit_act = QAction("Quit", self)
        quit_act.triggered.connect(QApplication.quit)
        self.tray_menu.addAction(show_act)
        self.tray_menu.addSeparator()
        self.tray_menu.addAction(quit_act)
        self.tray.setContextMenu(self.tray_menu)
        self.tray.show()
        self.tray.activated.connect(self._on_tray_activated)

        bridge.workflowsChanged.connect(self._update_tray_menu)

        if sys.platform == "win32":
            self.hotkey_mgr = GlobalHotkeyManager(self.winId())
            self.hotkey_mgr.register_all(bridge._workflows)
            bridge._hotkey_mgr = self.hotkey_mgr
            bridge.workflowsChanged.connect(lambda _: self.hotkey_mgr.register_all(bridge._workflows))
        else:
            self.hotkey_mgr = None

        self.schedule_checker = ScheduleChecker(self)
        self.schedule_checker.trigger_workflow.connect(self._on_scheduled)
        self.schedule_checker.update_workflows(bridge._workflows)
        bridge.workflowsChanged.connect(lambda _: self.schedule_checker.update_workflows(bridge._workflows))
        self.schedule_checker.start()

        self.update_checker = UpdateChecker(self)
        self.update_checker.update_available.connect(bridge.updateAvailable)
        self.update_checker.start()

        self.api_server = NexusAPIServer(self)
        self.api_server.start()

        self._tray_shown = False
        QTimer.singleShot(500, self._setup_tray)

    def _generate_icon(self):
        import base64
        global _LOGO_B64
        size = 256
        pm = QPixmap(size, size)
        pm.fill(Qt.transparent)
        
        if _LOGO_B64:
            pm.loadFromData(base64.b64decode(_LOGO_B64))
        else:
            from PySide6.QtGui import QPainter, QLinearGradient, QBrush, QPen, QColor, QPolygon
            from PySide6.QtCore import QPoint
            painter = QPainter(pm)
            painter.setRenderHint(QPainter.Antialiasing)
            # gradient background
            grad = QLinearGradient(0, 0, 0, size)
            grad.setColorAt(0, QColor("#7C73F0"))
            grad.setColorAt(1, QColor("#4F46E5"))
            painter.setBrush(QBrush(grad))
            painter.setPen(Qt.NoPen)
            painter.drawRoundedRect(0, 0, size, size, 48, 48)
            # draw node graphic
            cx = size // 2
            painter.setPen(QPen(QColor("#2D2B6B"), 8))
            painter.setBrush(Qt.NoBrush)
            # stem line
            painter.drawLine(cx, 60, cx, 130)
            # fork lines
            painter.drawLine(cx, 130, cx-60, 185)
            painter.drawLine(cx, 130, cx+60, 185)
            # top square
            painter.setBrush(QColor("#C4B5FD"))
            painter.setPen(Qt.NoPen)
            painter.drawRoundedRect(cx-25, 30, 50, 50, 10, 10)
            # bottom left circle
            painter.setBrush(QColor("#34D399"))
            painter.drawEllipse(cx-85, 175, 50, 50)
            # bottom right diamond
            painter.setBrush(QColor("#A5B4FC"))
            diamond = QPolygon([
                QPoint(cx+60, 175),
                QPoint(cx+85, 200),
                QPoint(cx+60, 225),
                QPoint(cx+35, 200),
            ])
            painter.drawPolygon(diamond)
            painter.end()
            
        self.app_icon_pixmap = pm
        self.app_icon = QIcon(pm)

    def _setup_tray(self):
        self.tray.hide()
        self.tray.setIcon(self.app_icon)
        self.tray.show()
        self._update_tray_menu()

    def _on_tray_activated(self, reason):
        if reason == QSystemTrayIcon.ActivationReason.DoubleClick:
            self.show()
            self.raise_()
            self.activateWindow()

    def _on_scheduled(self, name):
        self.tray.showMessage("Nexus", f"Launching '{name}' (scheduled)", QSystemTrayIcon.Information, 3000)
        self.bridge.runWorkflow(name)

    def _update_tray_menu(self, _=None):
        self.tray_menu.clear()

        show_act = QAction("Show Nexus", self)
        show_act.triggered.connect(lambda: (self.show(), self.raise_(), self.activateWindow()))
        self.tray_menu.addAction(show_act)
        self.tray_menu.addSeparator()

        workflows = self.bridge._workflows
        if workflows:
            for name, data in workflows.items():
                emoji = data.get("emoji", "▶")
                act = QAction(f"{emoji} {name}", self)
                act.triggered.connect(lambda checked=False, n=name: self.bridge.runWorkflow(n))
                self.tray_menu.addAction(act)
            self.tray_menu.addSeparator()

        quit_act = QAction("Quit Nexus", self)
        quit_act.triggered.connect(QApplication.quit)
        self.tray_menu.addAction(quit_act)

    def nativeEvent(self, event_type, message):
        if event_type == b"windows_generic_MSG" and getattr(self, 'hotkey_mgr', None):
            msg = wintypes.MSG.from_address(int(message))
            if msg.message == 0x0312:
                name = self.hotkey_mgr.get_name(msg.wParam)
                if name:
                    self.bridge.runWorkflow(name)
                    return True, 0
        return super().nativeEvent(event_type, message)

    def closeEvent(self, event):
        event.ignore()
        self.bridge._settings["geometry"] = self.saveGeometry().toBase64().data().decode()
        self.bridge._save_settings()
        self.hide()
        self.tray.show()
        if not self._tray_shown:
            self.tray.showMessage(
                "Nexus",
                "Nexus is running in the system tray. Right-click to launch workflows.",
                QSystemTrayIcon.MessageIcon.Information,
                2500
            )
            self._tray_shown = True

if __name__ == "__main__":
    app = QApplication(sys.argv)
    
    # FIX 1: Tell Windows this is a unique App so it shows the taskbar icon
    try:
        myappid = 'Faraz.Nexus.Launcher.2.0' 
        ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID(myappid)
    except Exception:
        pass

    app.setQuitOnLastWindowClosed(False)
    app.setApplicationName("Nexus")
    
    # FIX 2: Set the Application Window Icon explicitly
    # This logic finds the icon in the same folder as your installed EXE
    if getattr(sys, 'frozen', False):
        # If running as an EXE
        app_dir = os.path.dirname(sys.executable)
    else:
        # If running as a script
        app_dir = os.path.dirname(os.path.abspath(__file__))
    
    icon_path = os.path.join(app_dir, "nexus.ico")
    if os.path.exists(icon_path):
        app.setWindowIcon(QIcon(icon_path))

    bridge = NexusBridge()
    window = MainWindow(bridge)
    window.show()
    sys.exit(app.exec())

# BUILD EXE (no external files needed — all assets embedded):
# pip install pyinstaller platformdirs keyboard
# pyinstaller --onefile --windowed --name "Nexus" nexus.py
#
# Note: --icon flag is optional since icon is embedded in code.
# To use a real .ico for the EXE file icon only:
# pyinstaller --onefile --windowed --name "Nexus" --icon="nexus.ico" nexus.py
